"use client";

import * as m from "motion/react-m";
import { useId, useRef } from "react";

import { useIntersectionObserver } from "@/hooks/ui/useIntersectionObserver";
import { cn } from "@/lib/utils";

interface SplitTextBlurProps {
  text: string;
  className?: string;
  delay?: number;
  staggerDelay?: number;
  springConfig?: {
    stiffness: number;
    damping: number;
    mass: number;
  };
  yOffset?: number;
  disableIntersectionObserver?: boolean;
  as?: "h1" | "h2" | "h3" | "div";
  gradient?: string;
  showGlowTextBg?: boolean;
  lcpOptimized?: boolean;
}

const SplitTextBlur = ({
  text,
  className = "",
  delay = 1,
  staggerDelay = 0.1,
  springConfig = {
    stiffness: 400,
    damping: 70,
    mass: 1,
  },
  yOffset = 2,
  disableIntersectionObserver = false,
  gradient = "linear-gradient(to bottom, #a3a3a3, #ffffff)",
  showGlowTextBg = false,
  lcpOptimized = false,
  as = "div",
}: SplitTextBlurProps) => {
  const ref = useRef<HTMLDivElement>(null);
  const isVisible = useIntersectionObserver(ref, { threshold: 0.1 });

  const words = text.split(" ");

  const containerVariants = {
    hidden: { opacity: lcpOptimized ? 1 : 0 },
    visible: {
      opacity: 1,
      transition: {
        delay,
        when: "beforeChildren",
        staggerChildren: staggerDelay,
      },
    },
  };

  const wordVariants = {
    hidden: {
      opacity: lcpOptimized ? 1 : 0,
      filter: "blur(10px)",
      y: yOffset,
    },
    visible: {
      opacity: 1,
      filter: "blur(0px)",
      y: 0,
      transition: {
        type: "spring" as const,
        stiffness: springConfig.stiffness,
        damping: springConfig.damping,
        mass: springConfig.mass,
      },
    },
  };

  const shouldAnimate = disableIntersectionObserver || isVisible;
  const baseId = useId();

  const motionComponents = { h1: m.h1, h2: m.h2, h3: m.h3, div: m.div };
  const MotionComponent = motionComponents[as];

  const gradientStyle = {
    "--split-gradient": gradient,
  } as React.CSSProperties;

  return (
    <div className="relative" style={gradientStyle}>
      <MotionComponent
        ref={ref}
        initial="hidden"
        animate={shouldAnimate ? "visible" : "hidden"}
        variants={containerVariants}
        className={`${cn(className)} z-[10]`}
        style={{
          background: "var(--split-gradient)",
          WebkitBackgroundClip: "text",
          WebkitTextFillColor: "transparent",
          backgroundClip: "text",
        }}
      >
        {words.map((word, index) => (
          <m.span
            // biome-ignore lint/suspicious/noArrayIndexKey: mapping with word and base id and index
            key={baseId + word + index}
            variants={wordVariants}
            style={{
              willChange: "transform, opacity, filter",
              display: "inline-block",
              marginRight: index < words.length - 1 ? "0.25em" : "0",
              background: "inherit",
              WebkitBackgroundClip: "inherit",
              WebkitTextFillColor: "inherit",
              backgroundClip: "inherit",
              paddingBottom: "7px",
            }}
            className="font-serif p-[5px] pl-0"
          >
            {word}
          </m.span>
        ))}
      </MotionComponent>
      {showGlowTextBg && (
        <m.div
          ref={ref}
          initial="hidden"
          animate={shouldAnimate ? "visible" : "hidden"}
          variants={containerVariants}
          className={`${cn(className)} text-white blur-md absolute top-0 z-[-1]`}
        >
          {words.map((word, index) => (
            <m.span
              // biome-ignore lint/suspicious/noArrayIndexKey: mapping with word and base id and index
              key={baseId + word + index}
              variants={wordVariants}
              style={{
                willChange: "transform, opacity, filter",
                display: "inline-block",
                marginRight: index < words.length - 1 ? "0.25em" : "0",
                background: "inherit",
                WebkitBackgroundClip: "inherit",
                WebkitTextFillColor: "inherit",
                backgroundClip: "inherit",
                paddingBottom: "7px",
              }}
              className="font-serif"
            >
              {word}
            </m.span>
          ))}
        </m.div>
      )}
    </div>
  );
};

export { SplitTextBlur };

