                ? "text-black! px-1 hover:scale-105"
                : "text-white! px-1 hover:scale-105"
            }
            text={
              <div className="flex items-center gap-1.5">
                Sign Up <CircleArrowRight02Icon width={20} height={20} />
              </div>
