392	function useFloatingCta(
393	  phoneRef: React.RefObject<HTMLDivElement | null>,
394	): boolean {
395	  const [floating, setFloating] = useState(false);
396	
397	  useEffect(() => {
398	    const phone = phoneRef.current;
399	    if (!phone) return;
400	
401	    const update = (): void => {
402	      const phoneRect = phone.getBoundingClientRect();
403	      const vh = window.innerHeight;
404	      // Threshold is tuned so the floating button and its static-flow slot
405	      // line up vertically at the moment of switch — the visual position
406	      // doesn't jump.
407	      const phoneEnoughVisible = phoneRect.top < vh - 200;
408	      // The floating button sits at vh - 56 (bottom-6 + button height). The
409	      // static slot sits at phoneRect.bottom + 62 (flex gap-8 + pt-2 + half
410	      // button). The switch happens when the two y positions match.
411	      const phoneStillNearBottom = phoneRect.bottom > vh - 118;
412	      setFloating(phoneEnoughVisible && phoneStillNearBottom);
413	    };
414	
415	    update();
416	    window.addEventListener("scroll", update, { passive: true });
417	    window.addEventListener("resize", update);
418	    return () => {
419	      window.removeEventListener("scroll", update);
420	      window.removeEventListener("resize", update);
421	    };
422	  }, [phoneRef]);
423	
424	  return floating;
425	}
