430	function useStaggeredMessages(platform: Platform): ChatMessageItem[] {
431	  const allMessages = platform.demo.messages;
432	  const [visibleCount, setVisibleCount] = useState(1);
433	  const [showTyping, setShowTyping] = useState(false);
434	
435	  useEffect(() => {
436	    setVisibleCount(1);
437	    setShowTyping(false);
438	    if (allMessages.length <= 1) return;
439	
440	    const timers: ReturnType<typeof setTimeout>[] = [];
441	    let elapsed = 0;
442	    for (let i = 1; i < allMessages.length; i++) {
443	      elapsed += TYPING_DELAY_MS;
444	      timers.push(setTimeout(() => setShowTyping(true), elapsed));
445	      elapsed += TYPING_DURATION_MS;
446	      timers.push(
447	        setTimeout(() => {
448	          setShowTyping(false);
449	          setVisibleCount((c) => c + 1);
450	        }, elapsed),
451	      );
452	    }
453	
454	    return () => {
455	      for (const t of timers) clearTimeout(t);
456	    };
457	  }, [allMessages]);
458	
459	  return useMemo(() => {
460	    const real = allMessages.slice(0, visibleCount).map((m, i) => ({
461	      ...m,
462	      id: m.id ?? `msg-${i}`,
463	    }));
464	    if (!showTyping || visibleCount >= allMessages.length) return real;
465	    const next = allMessages[visibleCount];
466	    return [
467	      ...real,
468	      {
469	        id: `typing-${visibleCount}`,
470	        from: next.from,
471	        author: next.author,
472	        avatar: next.avatar,
473	        authorColor: next.authorColor,
474	        typing: true,
475	      },
476	    ];
477	  }, [allMessages, visibleCount, showTyping]);
478	}
