export default function FinalSection({
  showSocials = true,
  timeOfDay: timeOfDayProp,
  isDark: isDarkProp,
  onTextClick,
  onTimeChange,
}: {
  showSocials?: boolean;
  timeOfDay?: TimeOfDay;
  isDark?: boolean;
  onTextClick?: () => void;
  onTimeChange?: () => void;
}) {
  const [internalTimeOfDay, setInternalTimeOfDay] = useState<TimeOfDay>(() =>
    getTimeOfDay(),
  );
  const [internalClickCount, setInternalClickCount] = useState(0);

  const timeOfDay = timeOfDayProp ?? internalTimeOfDay;
  const isDark =
    isDarkProp !== undefined ? isDarkProp : isDarkTimeOfDay(timeOfDay);

  const handleInternalClick = () => {
    const next = internalClickCount + 1;
    setInternalClickCount(next);
    if (next % 3 === 0) {
      setInternalTimeOfDay((prev) => {
        const idx = TIME_OF_DAY_CYCLE.indexOf(prev);
        return TIME_OF_DAY_CYCLE[(idx + 1) % TIME_OF_DAY_CYCLE.length];
      });
    }
  };

  const handleTimeChange =
    onTimeChange ??
    (() => {
      setInternalTimeOfDay((prev) => {
        const idx = TIME_OF_DAY_CYCLE.indexOf(prev);
        return TIME_OF_DAY_CYCLE[(idx + 1) % TIME_OF_DAY_CYCLE.length];
      });
    });

  const wallpaper = SWISS_KID_WALLPAPERS[timeOfDay];

  const [previousTime, setPreviousTime] = useState<TimeOfDay | null>(null);
  const lastTimeRef = useRef<TimeOfDay>(timeOfDay);

  if (timeOfDay !== lastTimeRef.current) {
    setPreviousTime(lastTimeRef.current);
    lastTimeRef.current = timeOfDay;
  }

  const [shouldPreloadOthers, setShouldPreloadOthers] = useState(false);
  useEffect(() => {
    const t = setTimeout(() => setShouldPreloadOthers(true), 1200);
    return () => clearTimeout(t);
  }, []);

  return (
    <div className="relative z-1 m-0! flex min-h-screen w-full flex-col items-center justify-center gap-4 overflow-hidden px-4 sm:px-6">
      {shouldPreloadOthers && (
        <div
          aria-hidden="true"
          className="pointer-events-none fixed left-0 top-0 h-px w-px overflow-hidden opacity-0"
        >
          {Object.entries(SWISS_KID_WALLPAPERS)
            .filter(([t]) => t !== timeOfDay)
            .map(([t, { webp }]) => (
              <NextImage
                key={t}
                src={webp}
                alt=""
                width={1920}
                height={1080}
                sizes="100vw"
                priority
              />
            ))}
        </div>
      )}

      <div className="pointer-events-none absolute inset-x-0 bottom-0 z-10 h-[20vh] bg-linear-to-t from-background to-transparent" />
      <div className="pointer-events-none absolute inset-x-0 top-0 z-10 h-[30vh] bg-linear-to-b from-background to-transparent" />
      <div className="absolute bottom-6 right-6 z-[1002]">
        <TimeOfDayToggle timeOfDay={timeOfDay} onPress={handleTimeChange} />
      </div>

      {previousTime && (
        <div
          key={`prev-${previousTime}`}
          className="absolute bottom-0 left-0 right-0 z-0"
        >
          <ProgressiveImage
            webpSrc={SWISS_KID_WALLPAPERS[previousTime].webp}
            pngSrc={SWISS_KID_WALLPAPERS[previousTime].png}
            alt="Wallpaper"
            className="object-cover object-bottom"
            shouldHaveInitialFade={false}
            priority={false}
          />
        </div>
      )}

      <m.div
        key={timeOfDay}
        className="absolute bottom-0 left-0 right-0 z-0"
        initial={previousTime ? { clipPath: "circle(0% at 100% 50%)" } : false}
        animate={{ clipPath: "circle(150% at 100% 50%)" }}
        transition={{ duration: 0.5, ease: [0.65, 0, 0.35, 1] }}
        onAnimationComplete={() => setPreviousTime(null)}
      >
        <ProgressiveImage
          webpSrc={wallpaper.webp}
          pngSrc={wallpaper.png}
          alt="Wallpaper"
          className="object-cover object-bottom"
          shouldHaveInitialFade={true}
          priority={false}
        />
      </m.div>

      <div
        className={`relative z-20 ${showSocials ? "mb-30" : "mb-10"} flex h-full flex-col items-center justify-start gap-4`}
      >
        <div
          onClick={onTextClick ?? handleInternalClick}
          className="cursor-default select-none"
        >
          <TextSoftBlurIn
            text="Stop doing everything yourself."
            as="h2"
            className="z-10 text-center text-[2.2rem] font-medium sm:text-5xl md:text-8xl tracking-tight leading-snug text-white"
            gradient={
              isDark || timeOfDay === "morning"
                ? "linear-gradient(to bottom, #ffffff, #dbdbdb)"
                : "linear-gradient(to bottom, #837e88, #000000)"
            }
          />
        </div>

        <div
          className={`z-1 mb-6 max-w-(--breakpoint-md) px-4 py-0 text-center text-base leading-6 font-light tracking-tighter sm:px-0 sm:text-xl sm:leading-7 md:text-2xl ${isDark ? "text-white" : "text-white"}`}
        >
          Join thousands of professionals who gave their grunt work to GAIA.
        </div>
        <div className="flex gap-4">
          <GetStartedButton
            btnColor={isDark ? "#00bbff" : "#000000"}
            classname={
              isDark
                ? "text-black! text-lg h-12 px-2 rounded-2xl hover:scale-105"
                : "text-white! text-lg h-12 px-2 rounded-2xl hover:scale-105"
            }
            text="Try GAIA Free"
          />
          <GetStartedButton
            btnColor="#ffffff"
            classname="text-lg h-12 px-2 rounded-2xl hover:scale-105"
            text="Explore"
            href="/use-cases"
          />
        </div>
        <p
          className={`text-sm font-light mt-1 ${isDark ? "text-zinc-400" : "text-white/60"}`}
        >
          Free forever for personal use. No credit card.
        </p>

        {showSocials && (
          <div className="mt-4 flex items-center gap-3 sm:mt-6 sm:gap-2">
            {SOCIAL_LINKS.map(
              ({ href, ariaLabel, buttonProps, icon, label }, index) => {
                const color = `hover:text-[${buttonProps.color}]`;
                return (
                  <Tooltip
                    content={label}
                    placement="bottom"
                    key={index + href}
                  >
                    <Link
                      href={href}
                      aria-label={ariaLabel}
                      className={`flex w-10 scale-110 justify-center p-1 transition hover:scale-125 sm:w-10 sm:scale-125 sm:hover:scale-150 ${color}`}
                    >
                      {icon}
                    </Link>
                  </Tooltip>
                );
              },
            )}
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import {
  type CSSProperties,
  createElement,
  type ReactNode,
  useEffect,
  useId,
  useMemo,
  useRef,
  useState,
} from "react";

import { cn } from "@/lib/utils";

type AsTag = "h1" | "h2" | "h3" | "p" | "div" | "span";

interface TextSoftBlurInProps {
  text: string;
  as?: AsTag;
  className?: string;
  startDelay?: number;
  charStagger?: number;
  duration?: number;
  blur?: number;
  yOffset?: number;
  splitBy?: "char" | "word";
  immediate?: boolean;
  gradient?: string;
  threshold?: number;
}

const EASE = "cubic-bezier(0.22, 1, 0.36, 1)";

function useFreezeOnIntersect(
  ref: React.RefObject<HTMLElement | null>,
  threshold: number,
  skip: boolean,
): boolean {
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    if (skip) {
      const id = requestAnimationFrame(() => setVisible(true));
      return () => cancelAnimationFrame(id);
    }

    const node = ref.current;
    if (!node) return;

    if (typeof IntersectionObserver === "undefined") {
      setVisible(true);
      return;
    }

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry?.isIntersecting) {
          setVisible(true);
          observer.disconnect();
        }
      },
      { threshold },
    );

    observer.observe(node);
    return () => observer.disconnect();
  }, [ref, threshold, skip]);

  return visible;
}

export function TextSoftBlurIn({
  text,
  as = "div",
  className,
  startDelay = 0.05,
  charStagger = 0.025,
  duration = 0.9,
  blur = 12,
  yOffset = 16,
  splitBy = "char",
  immediate = false,
  gradient,
  threshold = 0.15,
}: TextSoftBlurInProps) {
  const ref = useRef<HTMLSpanElement>(null);
  const isVisible = useFreezeOnIntersect(ref, threshold, immediate);
  const baseId = useId();

  const parts = useMemo(() => {
    if (splitBy === "word") {
      const words = text.split(" ");
      return words.map((w, i) => (i < words.length - 1 ? `${w} ` : w));
    }
    return Array.from(text);
  }, [text, splitBy]);

  const totalAnimMs = useMemo(
    () => (startDelay + parts.length * charStagger + duration) * 1000,
    [startDelay, charStagger, duration, parts.length],
  );

  const [animDone, setAnimDone] = useState(false);
  useEffect(() => {
    if (!isVisible) return;
    const id = window.setTimeout(() => setAnimDone(true), totalAnimMs + 50);
    return () => window.clearTimeout(id);
  }, [isVisible, totalAnimMs]);

  const gradientStyle: CSSProperties | undefined = gradient
    ? {
        backgroundImage: gradient,
        WebkitBackgroundClip: "text",
        WebkitTextFillColor: "transparent",
        backgroundClip: "text",
        color: "transparent",
      }
    : undefined;

  const inner: ReactNode = (
    <span
      ref={ref}
      aria-hidden="true"
      className="inline-block"
      style={gradientStyle}
    >
      {parts.map((part, i) => {
        const delay = startDelay + i * charStagger;
        const charStyle: CSSProperties = {
          display: "inline-block",
          whiteSpace: "pre",
          opacity: isVisible ? 1 : 0,
          filter: isVisible ? "blur(0px)" : `blur(${blur}px)`,
          transform: isVisible ? "none" : `translateY(${yOffset}px)`,
          transition: `opacity ${duration}s ${EASE} ${delay}s, filter ${duration}s ${EASE} ${delay}s, transform ${duration}s ${EASE} ${delay}s`,
          willChange: animDone ? "auto" : "opacity, filter, transform",
          ...(gradient
            ? {
                backgroundImage: "inherit",
                WebkitBackgroundClip: "inherit",
                WebkitTextFillColor: "inherit",
                backgroundClip: "inherit",
              }
            : null),
        };
        return (
          <span
            // biome-ignore lint/suspicious/noArrayIndexKey: stable id + index
            key={`${baseId}-${i}`}
            style={charStyle}
          >
            {part}
          </span>
        );
      })}
    </span>
  );

  return createElement(
    as,
    { className: cn(className), "aria-label": text },
    inner,
  );
}

interface SoftBlurInBlockProps {
  children: ReactNode;
  as?: AsTag;
  className?: string;
  delay?: number;
  duration?: number;
  blur?: number;
  yOffset?: number;
  immediate?: boolean;
  threshold?: number;
}

export function SoftBlurInBlock({
